const fmt    = (n) => "₡" + Number(n||0).toLocaleString("es-CR",{minimumFractionDigits:0});
const fmtPct = (n) => Number(n||0).toFixed(1) + "%";
const now    = new Date();

// ── shared input styles ───────────────────────────────────────────────────
const INP = {border:"1px solid #DDD",borderRadius:8,padding:"9px 12px",fontSize:13,outline:"none",background:"#FAFAFA",width:"100%",boxSizing:"border-box"};
const LBL = {fontSize:10,color:"#777",fontWeight:700,display:"block",marginBottom:4,letterSpacing:0.5};

// ── StatCard ──────────────────────────────────────────────────────────────
function StatCard({ label, value, color, icon }) {
  return (
    <div style={{background:"#fff",border:"1px solid #E8E8E8",borderRadius:12,padding:"18px 20px",display:"flex",alignItems:"center",gap:14,boxShadow:"0 1px 4px rgba(0,0,0,0.06)"}}>
      <div style={{width:46,height:46,borderRadius:12,background:color+"18",display:"flex",alignItems:"center",justifyContent:"center",fontSize:20}}>{icon}</div>
      <div>
        <div style={{fontSize:10,color:"#888",fontWeight:700,letterSpacing:1,textTransform:"uppercase"}}>{label}</div>
        <div style={{fontSize:20,fontWeight:800,color:"#1a1a1a",marginTop:1}}>{value}</div>
      </div>
    </div>
  );
}

// ── BarChart ──────────────────────────────────────────────────────────────
function BarChart({ data, color, maxVal }) {
  if (!data || data.length === 0) return <div style={{color:"#bbb",textAlign:"center",padding:20}}>Sin datos.</div>;
  return (
    <div style={{display:"flex",flexDirection:"column",gap:7}}>
      {data.map(({label,value}) => {
        const pct = maxVal > 0 ? (value / maxVal * 100) : 0;
        return (
          <div key={label} style={{display:"flex",alignItems:"center",gap:10}}>
            <div style={{width:120,fontSize:11,color:"#555",textAlign:"right",flexShrink:0,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{label}</div>
            <div style={{flex:1,background:"#F0F0F0",borderRadius:4,height:20,overflow:"hidden"}}>
              <div style={{width:pct+"%",background:color,height:"100%",borderRadius:4,transition:"width 0.5s",minWidth:pct>0?6:0}}/>
            </div>
            <div style={{width:95,fontSize:12,fontWeight:700,color:color,textAlign:"right"}}>{fmt(value)}</div>
          </div>
        );
      })}
    </div>
  );
}

// ── DonutChart ────────────────────────────────────────────────────────────
function DonutChart({ slices, labels, colors }) {
  const total = slices.reduce((s,v)=>s+v,0) || 1;
  let start = 0;
  const cx=55, cy=55, r=42, ir=24, size=110;
  const segments = slices.map((v,i) => {
    const pct = v / total;
    const angle = pct * 2 * Math.PI;
    const x1=cx+r*Math.sin(start), y1=cy-r*Math.cos(start);
    const x2=cx+r*Math.sin(start+angle), y2=cy-r*Math.cos(start+angle);
    const ix1=cx+ir*Math.sin(start), iy1=cy-ir*Math.cos(start);
    const ix2=cx+ir*Math.sin(start+angle), iy2=cy-ir*Math.cos(start+angle);
    const large = pct > 0.5 ? 1 : 0;
    const d = `M ${x1} ${y1} A ${r} ${r} 0 ${large} 1 ${x2} ${y2} L ${ix2} ${iy2} A ${ir} ${ir} 0 ${large} 0 ${ix1} ${iy1} Z`;
    start += angle;
    return { d, color: colors[i % colors.length], pct: Math.round(pct*100), label: labels[i], value: v };
  });
  return (
    <div style={{display:"flex",alignItems:"center",gap:24,flexWrap:"wrap"}}>
      <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`} style={{flexShrink:0}}>
        {segments.map((s,i)=><path key={i} d={s.d} fill={s.color}/>)}
      </svg>
      <div style={{display:"flex",flexDirection:"column",gap:7}}>
        {segments.map((s,i)=>(
          <div key={i} style={{display:"flex",alignItems:"center",gap:8}}>
            <div style={{width:10,height:10,borderRadius:2,background:s.color,flexShrink:0}}/>
            <span style={{fontSize:12,color:"#555"}}>{s.label}</span>
            <span style={{fontSize:12,fontWeight:700,color:s.color,marginLeft:4}}>{s.pct}%</span>
            <span style={{fontSize:11,color:"#aaa"}}>({fmt(s.value)})</span>
          </div>
        ))}
      </div>
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════════════
// RESUMEN TAB
// ═══════════════════════════════════════════════════════════════════════════
function ResumenTab({ restaurant, gastos, ventas }) {
  const totalGastos = gastos.reduce((s,r)=>s+parseFloat(r.monto||0),0);
  const totalVentas = ventas.reduce((s,r)=>s+(r.total||0),0);
  const utilidad    = totalVentas - totalGastos;
  const tv = ventas.reduce((s,r)=>s+(r.tarjeta||0),0);
  const te = ventas.reduce((s,r)=>s+(r.efectivo||0),0);
  const tt = ventas.reduce((s,r)=>s+(r.transferencia||0),0);

  return (
    <div>
      <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(175px,1fr))",gap:13,marginBottom:20}}>
        <StatCard label="Ventas"         value={fmt(totalVentas)} color={restaurant.color} icon="📈"/>
        <StatCard label="Gastos"         value={fmt(totalGastos)} color={restaurant.color} icon="💸"/>
        <StatCard label="Utilidad Neta"  value={fmt(utilidad)}    color={utilidad>=0?"#27AE60":"#E74C3C"} icon="💰"/>
        <StatCard label="Reg. Ventas"    value={ventas.length}    color={restaurant.color} icon="🧾"/>
        <StatCard label="Reg. Gastos"    value={gastos.length}    color={restaurant.color} icon="📁"/>
      </div>

      {ventas.length > 0 && (
        <div style={{background:"#fff",border:"1px solid #E8E8E8",borderRadius:12,padding:"18px 22px",marginBottom:16,boxShadow:"0 1px 4px rgba(0,0,0,0.06)"}}>
          <div style={{fontSize:11,fontWeight:700,color:"#555",marginBottom:14,letterSpacing:0.5}}>DESGLOSE DE VENTAS</div>
          <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:12}}>
            {[{l:"💳 Tarjeta",v:tv},{l:"💵 Efectivo",v:te},{l:"🏦 Transferencia",v:tt}].map(({l,v})=>(
              <div key={l} style={{textAlign:"center",padding:"12px 8px",background:"#F8F8F8",borderRadius:10}}>
                <div style={{fontSize:12,color:"#666",marginBottom:4}}>{l}</div>
                <div style={{fontSize:16,fontWeight:800,color:restaurant.color}}>{fmt(v)}</div>
                <div style={{fontSize:11,color:"#aaa"}}>{fmtPct(totalVentas>0?v/totalVentas*100:0)}</div>
              </div>
            ))}
          </div>
        </div>
      )}

      <div style={{background:"#fff",border:"1px solid #E8E8E8",borderRadius:12,padding:"18px 22px",boxShadow:"0 1px 4px rgba(0,0,0,0.06)"}}>
        <div style={{fontSize:11,fontWeight:700,color:"#555",marginBottom:14,letterSpacing:0.5}}>ÚLTIMOS GASTOS</div>
        {gastos.length === 0
          ? <div style={{textAlign:"center",padding:"36px 0",color:"#bbb"}}>Sin gastos registrados.</div>
          : <table style={{width:"100%",borderCollapse:"collapse",fontSize:12}}>
              <thead><tr style={{background:"#F8F8F8"}}>
                {["Fecha","Tipo","Subcategoría","Monto"].map(h=><th key={h} style={{padding:"7px 10px",textAlign:"left",fontSize:10,color:"#888",fontWeight:700}}>{h}</th>)}
              </tr></thead>
              <tbody>
                {gastos.slice(0,6).map(r=>(
                  <tr key={r.id} style={{borderTop:"1px solid #F0F0F0"}}>
                    <td style={{padding:"8px 10px"}}>{r.fecha}</td>
                    <td style={{padding:"8px 10px"}}>{r.tipo}</td>
                    <td style={{padding:"8px 10px",color:"#888"}}>{r.subcategoria||r.categoriaProveedor||"—"}</td>
                    <td style={{padding:"8px 10px",fontWeight:700,color:restaurant.color}}>{fmt(r.monto)}</td>
                  </tr>
                ))}
              </tbody>
            </table>}
      </div>
    </div>
  );
}

