// VENTAS TAB
// ═══════════════════════════════════════════════════════════════════════════
function VentasTab({ restaurant, ventas, setVentas }) {
  const [form, setForm] = useState({fecha:"",tarjeta:"",efectivo:"",transferencia:"",descripcion:""});

  const agregar = () => {
    if (!form.fecha) return;
    const t=parseFloat(form.tarjeta||0), e=parseFloat(form.efectivo||0), tr=parseFloat(form.transferencia||0);
    if (t+e+tr === 0) return;
    setVentas(prev=>[{...form,tarjeta:t,efectivo:e,transferencia:tr,total:t+e+tr,id:Date.now()},...prev]);
    setForm({fecha:"",tarjeta:"",efectivo:"",transferencia:"",descripcion:""});
  };

  const eliminar = (id) => setVentas(prev=>prev.filter(r=>r.id!==id));
  const totalV  = ventas.reduce((s,r)=>s+r.total,0);
  const totalT  = ventas.reduce((s,r)=>s+r.tarjeta,0);
  const totalE  = ventas.reduce((s,r)=>s+r.efectivo,0);
  const totalTr = ventas.reduce((s,r)=>s+r.transferencia,0);
  const subTotal = parseFloat(form.tarjeta||0)+parseFloat(form.efectivo||0)+parseFloat(form.transferencia||0);

  return (
    <div style={{display:"grid",gridTemplateColumns:"300px 1fr",gap:18}}>
      <div style={{background:"#fff",border:"1px solid #E8E8E8",borderRadius:12,padding:20,boxShadow:"0 1px 4px rgba(0,0,0,0.06)",display:"flex",flexDirection:"column",gap:12}}>
        <div style={{fontSize:12,fontWeight:700,color:"#555",letterSpacing:0.5}}>REGISTRAR VENTA</div>
        <div><label style={LBL}>FECHA *</label><input type="date" style={INP} value={form.fecha} onChange={e=>setForm(f=>({...f,fecha:e.target.value}))}/></div>
        <div style={{background:"#F8F8F8",borderRadius:10,padding:"12px 14px",display:"flex",flexDirection:"column",gap:10}}>
          <div style={{fontSize:10,fontWeight:700,color:"#888",letterSpacing:0.5}}>FORMAS DE PAGO</div>
          {[{key:"tarjeta",label:"💳 Tarjeta"},{key:"efectivo",label:"💵 Efectivo"},{key:"transferencia",label:"🏦 Transferencia"}].map(({key,label})=>(
            <div key={key}><label style={LBL}>{label}</label>
              <input type="number" style={INP} placeholder="0" value={form[key]} onChange={e=>setForm(f=>({...f,[key]:e.target.value}))}/>
            </div>
          ))}
        </div>
        {subTotal > 0 && (
          <div style={{background:restaurant.color+"12",borderRadius:8,padding:"10px 14px",textAlign:"center"}}>
            <div style={{fontSize:10,color:restaurant.color,fontWeight:700}}>TOTAL A REGISTRAR</div>
            <div style={{fontSize:18,fontWeight:800,color:restaurant.color}}>{fmt(subTotal)}</div>
          </div>
        )}
        <div><label style={LBL}>NOTAS</label><input type="text" style={INP} placeholder="Opcional..." value={form.descripcion} onChange={e=>setForm(f=>({...f,descripcion:e.target.value}))}/></div>
        <button onClick={agregar} style={{background:restaurant.color,color:"#fff",border:"none",borderRadius:8,padding:"11px 0",fontWeight:700,fontSize:14,cursor:"pointer"}}>+ Registrar Venta</button>
      </div>

      <div style={{background:"#fff",border:"1px solid #E8E8E8",borderRadius:12,padding:20,boxShadow:"0 1px 4px rgba(0,0,0,0.06)"}}>
        {ventas.length > 0 && (
          <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:10,marginBottom:16}}>
            {[{l:"Total",v:totalV},{l:"Tarjeta",v:totalT},{l:"Efectivo",v:totalE},{l:"Transferencia",v:totalTr}].map(({l,v})=>(
              <div key={l} style={{background:"#F8F8F8",borderRadius:10,padding:"10px 12px",textAlign:"center"}}>
                <div style={{fontSize:10,color:"#888",fontWeight:700}}>{l.toUpperCase()}</div>
                <div style={{fontSize:14,fontWeight:800,color:restaurant.color,marginTop:2}}>{fmt(v)}</div>
              </div>
            ))}
          </div>
        )}
        <div style={{fontSize:11,fontWeight:700,color:"#555",marginBottom:12,letterSpacing:0.5}}>HISTORIAL DE VENTAS</div>
        {ventas.length === 0
          ? <div style={{textAlign:"center",padding:"48px 0",color:"#bbb"}}>📈 Sin ventas registradas.</div>
          : <div style={{overflowX:"auto"}}>
              <table style={{width:"100%",borderCollapse:"collapse",fontSize:12}}>
                <thead><tr style={{background:"#F8F8F8"}}>
                  {["Fecha","💳 Tarjeta","💵 Efectivo","🏦 Transf.","Total","Notas",""].map(h=><th key={h} style={{padding:"7px 10px",textAlign:"left",fontSize:10,color:"#888",fontWeight:700,whiteSpace:"nowrap"}}>{h}</th>)}
                </tr></thead>
                <tbody>
                  {ventas.map(r=>(
                    <tr key={r.id} style={{borderTop:"1px solid #F0F0F0"}}>
                      <td style={{padding:"8px 10px",whiteSpace:"nowrap"}}>{r.fecha}</td>
                      <td style={{padding:"8px 10px"}}>{r.tarjeta>0?fmt(r.tarjeta):"—"}</td>
                      <td style={{padding:"8px 10px"}}>{r.efectivo>0?fmt(r.efectivo):"—"}</td>
                      <td style={{padding:"8px 10px"}}>{r.transferencia>0?fmt(r.transferencia):"—"}</td>
                      <td style={{padding:"8px 10px",fontWeight:800,color:restaurant.color}}>{fmt(r.total)}</td>
                      <td style={{padding:"8px 10px",color:"#aaa",maxWidth:120,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{r.descripcion||"—"}</td>
                      <td style={{padding:"8px 10px"}}><button onClick={()=>eliminar(r.id)} style={{background:"#FEE2E2",border:"none",borderRadius:6,padding:"3px 8px",cursor:"pointer",color:"#DC2626",fontSize:11}}>✕</button></td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>}
      </div>
    </div>
  );
}

