// FACTURAS — CAPTURA POR CÁMARA
// ═══════════════════════════════════════════════════════════════════════════
function FacturaCamaraTab({ restaurant, setGastos }) {
  const [fase, setFase] = useState("inicio"); // inicio | camara | preview | procesando | revision
  const [imgSrc, setImgSrc] = useState(null);
  const [ocrTexto, setOcrTexto] = useState("");
  const [form, setForm] = useState({
    fecha: new Date().toISOString().split("T")[0],
    tipo: "Proveedores",
    monto: "",
    nombreProveedor: "",
    categoriaProveedor: "Alimentos",
    descripcion: "",
  });
  const videoRef = useRef(null);
  const canvasRef = useRef(null);
  const streamRef = useRef(null);
  const fileRef = useRef(null);

  useEffect(() => () => { streamRef.current && streamRef.current.getTracks().forEach(t => t.stop()); }, []);

  const iniciarCamara = async () => {
    try {
      const s = await navigator.mediaDevices.getUserMedia({ video: { facingMode: "environment" }, audio: false });
      streamRef.current = s;
      videoRef.current.srcObject = s;
      await videoRef.current.play();
      setFase("camara");
    } catch {
      fileRef.current.click();
    }
  };

  const detenerCamara = () => { streamRef.current && streamRef.current.getTracks().forEach(t => t.stop()); };

  const tomarFoto = () => {
    const v = videoRef.current, c = canvasRef.current;
    c.width = v.videoWidth; c.height = v.videoHeight;
    c.getContext("2d").drawImage(v, 0, 0);
    setImgSrc(c.toDataURL("image/jpeg", 0.85));
    detenerCamara();
    setFase("preview");
  };

  const onFileChange = (e) => {
    const f = e.target.files[0]; if (!f) return;
    const r = new FileReader();
    r.onload = (ev) => { setImgSrc(ev.target.result); setFase("preview"); };
    r.readAsDataURL(f);
  };

  const cargarTesseract = () => new Promise((res, rej) => {
    if (window.Tesseract) { res(); return; }
    const s = document.createElement("script");
    s.src = "https://cdn.jsdelivr.net/npm/tesseract.js@4/dist/tesseract.min.js";
    s.onload = res; s.onerror = rej;
    document.head.appendChild(s);
  });

  const parsearTexto = (txt) => {
    const lines = txt.split("\n").map(l => l.trim()).filter(Boolean);
    const up = txt.toUpperCase();
    const result = {};
    // Monto: buscar TOTAL / MONTO seguido de número
    const mMatch = up.match(/(?:TOTAL|MONTO|IMPORTE|COBRO)[^\d]*([\d][,\d]*\.?\d*)/);
    if (mMatch) result.monto = mMatch[1].replace(/,/g, "");
    // Fecha dd/mm/yyyy o yyyy-mm-dd
    const fMatch = txt.match(/(\d{2})[\/\-](\d{2})[\/\-](\d{4})/);
    if (fMatch) result.fecha = `${fMatch[3]}-${fMatch[2]}-${fMatch[1]}`;
    const fMatch2 = txt.match(/(\d{4})[\/\-](\d{2})[\/\-](\d{2})/);
    if (!fMatch && fMatch2) result.fecha = `${fMatch2[1]}-${fMatch2[2]}-${fMatch2[3]}`;
    // Proveedor: primera línea larga con letras
    const prov = lines.find(l => l.length > 6 && /[A-Za-záéíóúÁÉÍÓÚñÑ]/.test(l));
    if (prov) result.nombreProveedor = prov.substring(0, 60);
    // Descripción: primeras líneas útiles
    result.descripcion = lines.slice(0, 6).join(" — ").substring(0, 150);
    return result;
  };

  const procesar = async () => {
    setFase("procesando");
    try {
      await cargarTesseract();
      const { data: { text } } = await window.Tesseract.recognize(imgSrc, "spa", {
        logger: () => {}
      });
      setOcrTexto(text);
      const parsed = parsearTexto(text);
      setForm(f => ({ ...f, ...parsed }));
      setFase("revision");
    } catch (e) {
      alert("Error al procesar la imagen. Verifique su conexión e intente de nuevo.");
      setFase("preview");
    }
  };

  const guardar = () => {
    if (!form.monto) { alert("Ingrese el monto"); return; }
    const gasto = {
      id: Date.now(),
      fecha: form.fecha,
      tipo: form.tipo,
      subcategoria: "",
      monto: form.monto,
      nombreProveedor: form.nombreProveedor,
      categoriaProveedor: form.categoriaProveedor,
      descripcion: form.descripcion,
    };
    setGastos(prev => [gasto, ...prev]);
    setImgSrc(null); setOcrTexto(""); setFase("inicio");
    setForm({ fecha: new Date().toISOString().split("T")[0], tipo: "Proveedores", monto: "", nombreProveedor: "", categoriaProveedor: "Alimentos", descripcion: "" });
    alert("Gasto registrado correctamente.");
  };

  const inputStyle = { width:"100%", padding:"9px 12px", borderRadius:8, border:"1px solid #e5e7eb", fontSize:13, boxSizing:"border-box", background:"#fff" };
  const labelStyle = { fontSize:12, fontWeight:600, color:"#374151", marginBottom:4, display:"block" };

  return (
    <div style={{maxWidth:560, margin:"0 auto", padding:"8px 0"}}>
      <canvas ref={canvasRef} style={{display:"none"}}/>
      <input ref={fileRef} type="file" accept="image/*" capture="environment" style={{display:"none"}} onChange={onFileChange}/>

      {fase === "inicio" && (
        <div style={{textAlign:"center", padding:"40px 20px"}}>
          <div style={{fontSize:56, marginBottom:16}}>📷</div>
          <div style={{fontSize:17, fontWeight:700, color:"#1a1a2e", marginBottom:8}}>Captura de Factura</div>
          <div style={{fontSize:13, color:"#6b7280", marginBottom:32}}>Toma una foto de la factura y extraemos los datos automáticamente</div>
          <button onClick={iniciarCamara} style={{background: restaurant.color, color:"#fff", border:"none", borderRadius:12, padding:"14px 32px", fontSize:15, fontWeight:700, cursor:"pointer"}}>
            📷 Abrir Cámara
          </button>
          <div style={{marginTop:12, fontSize:12, color:"#9ca3af"}}>Si no hay cámara disponible, se abrirá el selector de archivos</div>
        </div>
      )}

      {fase === "camara" && (
        <div style={{textAlign:"center"}}>
          <video ref={videoRef} style={{width:"100%", maxWidth:480, borderRadius:12, display:"block", margin:"0 auto"}} playsInline muted/>
          <div style={{marginTop:16, display:"flex", gap:12, justifyContent:"center"}}>
            <button onClick={tomarFoto} style={{background: restaurant.color, color:"#fff", border:"none", borderRadius:12, padding:"12px 28px", fontSize:14, fontWeight:700, cursor:"pointer"}}>
              📸 Tomar Foto
            </button>
            <button onClick={()=>{detenerCamara(); setFase("inicio");}} style={{background:"#f3f4f6", color:"#374151", border:"none", borderRadius:12, padding:"12px 20px", fontSize:14, cursor:"pointer"}}>
              Cancelar
            </button>
          </div>
        </div>
      )}

      {fase === "preview" && (
        <div style={{textAlign:"center"}}>
          <img src={imgSrc} style={{width:"100%", maxWidth:480, borderRadius:12, display:"block", margin:"0 auto", border:"2px solid #e5e7eb"}} alt="Factura"/>
          <div style={{marginTop:16, display:"flex", gap:12, justifyContent:"center"}}>
            <button onClick={procesar} style={{background: restaurant.color, color:"#fff", border:"none", borderRadius:12, padding:"12px 28px", fontSize:14, fontWeight:700, cursor:"pointer"}}>
              ⚙️ Procesar Factura
            </button>
            <button onClick={()=>setFase("inicio")} style={{background:"#f3f4f6", color:"#374151", border:"none", borderRadius:12, padding:"12px 20px", fontSize:14, cursor:"pointer"}}>
              Nueva Foto
            </button>
          </div>
        </div>
      )}

      {fase === "procesando" && (
        <div style={{textAlign:"center", padding:"60px 20px"}}>
          <div style={{fontSize:48, marginBottom:16}}>🔍</div>
          <div style={{fontSize:15, fontWeight:700, color:"#1a1a2e", marginBottom:8}}>Leyendo factura...</div>
          <div style={{fontSize:13, color:"#6b7280"}}>Extrayendo información con OCR, por favor espere</div>
        </div>
      )}

      {fase === "revision" && (
        <div>
          <div style={{display:"flex", gap:12, alignItems:"flex-start", marginBottom:20}}>
            <img src={imgSrc} style={{width:100, borderRadius:8, border:"1px solid #e5e7eb", flexShrink:0}} alt="Factura"/>
            <div style={{flex:1}}>
              <div style={{fontSize:13, fontWeight:700, color:"#1a1a2e", marginBottom:4}}>Datos extraídos</div>
              <div style={{fontSize:12, color:"#6b7280"}}>Revise y corrija si es necesario antes de guardar</div>
            </div>
          </div>
          <div style={{display:"grid", gridTemplateColumns:"1fr 1fr", gap:12, marginBottom:12}}>
            <div>
              <label style={labelStyle}>Fecha</label>
              <input style={inputStyle} type="date" value={form.fecha} onChange={e=>setForm(f=>({...f,fecha:e.target.value}))}/>
            </div>
            <div>
              <label style={labelStyle}>Monto (₡)</label>
              <input style={inputStyle} type="number" value={form.monto} onChange={e=>setForm(f=>({...f,monto:e.target.value}))} placeholder="0"/>
            </div>
          </div>
          <div style={{marginBottom:12}}>
            <label style={labelStyle}>Tipo de Gasto</label>
            <select style={inputStyle} value={form.tipo} onChange={e=>setForm(f=>({...f,tipo:e.target.value}))}>
              {["Proveedores","Servicios","Administrativos","Mantenimiento","Otros"].map(t=><option key={t}>{t}</option>)}
            </select>
          </div>
          <div style={{marginBottom:12}}>
            <label style={labelStyle}>Proveedor</label>
            <input style={inputStyle} value={form.nombreProveedor} onChange={e=>setForm(f=>({...f,nombreProveedor:e.target.value}))} placeholder="Nombre del proveedor"/>
          </div>
          <div style={{marginBottom:12}}>
            <label style={labelStyle}>Categoría</label>
            <select style={inputStyle} value={form.categoriaProveedor} onChange={e=>setForm(f=>({...f,categoriaProveedor:e.target.value}))}>
              {["Alimentos","Bebida","Insumos","Servicios","Otros"].map(c=><option key={c}>{c}</option>)}
            </select>
          </div>
          <div style={{marginBottom:20}}>
            <label style={labelStyle}>Descripción</label>
            <textarea style={{...inputStyle, minHeight:70, resize:"vertical"}} value={form.descripcion} onChange={e=>setForm(f=>({...f,descripcion:e.target.value}))} placeholder="Descripción del gasto"/>
          </div>
          <div style={{display:"flex", gap:12}}>
            <button onClick={guardar} style={{flex:1, background: restaurant.color, color:"#fff", border:"none", borderRadius:12, padding:"13px 0", fontSize:14, fontWeight:700, cursor:"pointer"}}>
              💾 Guardar Gasto
            </button>
            <button onClick={()=>setFase("inicio")} style={{background:"#f3f4f6", color:"#374151", border:"none", borderRadius:12, padding:"13px 20px", fontSize:14, cursor:"pointer"}}>
              Nueva
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════════════
// HOME
// ═══════════════════════════════════════════════════════════════════════════
export default function App() {
  const [selected, setSelected] = useState(null);
  if (selected) return <RestauranteDashboard restaurant={selected} onBack={()=>setSelected(null)}/>;

  const guardarArchivo = () => {
    const data = {};
    for (let i = 0; i < localStorage.length; i++) {
      const k = localStorage.key(i);
      if (k && k.startsWith("zocalo_r")) {
        try { data[k] = JSON.parse(localStorage.getItem(k)); } catch {}
      }
    }
    // Leer fuente de la app desde el script tag de Babel en la página actual
    const appSrc = (document.querySelector('script[type="text/babel"]') || {}).textContent || '';
    // Leer librerías incrustadas (scripts sin tipo que no sean de datos)
    const libTags = Array.from(document.head.querySelectorAll('script:not([type])')).filter(s =>
      !s.textContent.includes('__ZOCALO_DATA__') && !s.textContent.includes('__ZOCALO_TEMPLATE__')
    ).map(s => '<scr' + 'ipt>' + s.textContent.replace(/<\/script>/gi, '<\\/script>') + '<' + '/script>').join('\n');
    const dataLine = 'window.__ZOCALO_DATA__ = ' + JSON.stringify(data) + ';';
    const appEsc = appSrc.replace(/<\/script>/gi, '<\\/script>');
    const html = [
      '<!DOCTYPE html>',
      '<html lang="es">',
      '<head>',
      '  <meta charset="UTF-8"/>',
      '  <meta name="viewport" content="width=device-width, initial-scale=1.0"/>',
      '  <title>Zócalo Admin</title>',
      libTags,
      '  <scr' + 'ipt>' + dataLine + '<' + '/script>',
      '</head>',
      '<body style="margin:0;padding:0">',
      '  <div id="root"></div>',
      '  <scr' + 'ipt type="text/babel" data-presets="react">' + appEsc + '<' + '/script>',
      '</body>',
      '</html>'
    ].join('\n');
    const blob = new Blob([html], {type: 'text/html;charset=utf-8'});
    const a = document.createElement('a');
    a.href = URL.createObjectURL(blob);
    a.download = 'zocalo-admin-' + new Date().toISOString().split('T')[0] + '.html';
    a.click();
    URL.revokeObjectURL(a.href);
  };

  return (
    <div style={{minHeight:"100vh",background:"#111827",fontFamily:"'Inter','Segoe UI',sans-serif"}}>
      <div style={{background:"linear-gradient(160deg,#1a1a2e 0%,#16213e 60%,#0f3460 100%)",padding:"44px 32px 48px",textAlign:"center",borderBottom:"1px solid rgba(255,255,255,0.08)",position:"relative"}}>
        <button onClick={guardarArchivo} style={{position:"absolute",top:16,right:16,background:"rgba(255,255,255,0.08)",border:"1px solid rgba(255,255,255,0.2)",borderRadius:10,color:"#fff",fontSize:12,fontWeight:700,padding:"8px 14px",cursor:"pointer",letterSpacing:0.5}} title="Descargar archivo con todos los datos guardados">💾 Exportar</button>
        <img src={LOGO_SRC} alt="ZOCALO" style={{height:130,objectFit:"contain",marginBottom:16,filter:"drop-shadow(0 4px 24px rgba(0,0,0,0.5))"}}/>
        <div style={{fontSize:13,color:"rgba(255,255,255,0.5)",letterSpacing:3,textTransform:"uppercase",marginBottom:6}}>Sistema Administrativo y Financiero</div>
        <div style={{fontSize:11,color:"rgba(255,255,255,0.3)",letterSpacing:1}}>{new Date().toLocaleDateString("es-CR",{weekday:"long",year:"numeric",month:"long",day:"numeric"})}</div>
      </div>

      <div style={{maxWidth:960,margin:"0 auto",padding:"36px 20px 48px"}}>
        <div style={{textAlign:"center",marginBottom:32}}>
          <div style={{fontSize:13,color:"rgba(255,255,255,0.35)",letterSpacing:2}}>SELECCIONE UN RESTAURANTE</div>
        </div>

        <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(260px,1fr))",gap:20}}>
          {RESTAURANTS.map(r=>(
            <button key={r.id} onClick={()=>setSelected(r)} style={{
              background:"rgba(255,255,255,0.04)",border:"1px solid rgba(255,255,255,0.1)",
              borderRadius:16,padding:0,cursor:"pointer",textAlign:"left",transition:"all 0.25s",overflow:"hidden"
            }}
              onMouseEnter={e=>{e.currentTarget.style.transform="translateY(-5px)";e.currentTarget.style.background=r.color+"22";e.currentTarget.style.borderColor=r.color+"60";e.currentTarget.style.boxShadow=`0 16px 40px ${r.color}30`;}}
              onMouseLeave={e=>{e.currentTarget.style.transform="translateY(0)";e.currentTarget.style.background="rgba(255,255,255,0.04)";e.currentTarget.style.borderColor="rgba(255,255,255,0.1)";e.currentTarget.style.boxShadow="none";}}
            >
              <div style={{height:5,background:`linear-gradient(90deg,${r.color},${r.accent})`}}/>
              <div style={{padding:"22px 22px 18px",display:"flex",alignItems:"flex-start",gap:16}}>
                <div style={{width:58,height:58,borderRadius:12,background:`linear-gradient(135deg,${r.color},${r.accent})`,display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0,padding:7,boxSizing:"border-box"}}>
                  <img src={LOGO_SRC} alt="Z" style={{width:"100%",height:"100%",objectFit:"contain",filter:"brightness(0) invert(1)"}}/>
                </div>
                <div style={{flex:1}}>
                  <div style={{fontSize:17,fontWeight:800,color:"#fff",marginBottom:5}}>{r.nombre}</div>
                  <div style={{fontSize:11,color:"rgba(255,255,255,0.45)",lineHeight:1.5}}><span style={{color:"rgba(255,255,255,0.6)",fontWeight:600}}>Razón Social:</span><br/>{r.razonSocial}</div>
                </div>
              </div>
              <div style={{padding:"8px 22px 16px",display:"flex",justifyContent:"flex-end"}}>
                <div style={{fontSize:12,fontWeight:700,color:r.accent}}>Ingresar →</div>
              </div>
            </button>
          ))}
        </div>

        <div style={{marginTop:36,background:"rgba(255,255,255,0.05)",borderRadius:12,border:"1px solid rgba(255,255,255,0.08)",padding:"16px 28px",display:"flex",justifyContent:"space-around"}}>
          {[{label:"Restaurantes",value:"4",icon:"🏪"},{label:"Módulos",value:"6",icon:"📦"},{label:"Sistema",value:"En línea",icon:"🟢"}].map(s=>(
            <div key={s.label} style={{textAlign:"center"}}>
              <div style={{fontSize:18,marginBottom:4}}>{s.icon}</div>
              <div style={{fontSize:17,fontWeight:800,color:"#fff"}}>{s.value}</div>
              <div style={{fontSize:10,color:"rgba(255,255,255,0.35)",fontWeight:600,letterSpacing:0.5}}>{s.label.toUpperCase()}</div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}
